import{_ as e,o as l,c as n,a2 as s}from"./chunks/framework.BnBoz4Zl.js";const u=JSON.parse('{"title":"第 11 章 Word、Excel、PPT 办公交付与格式检查","description":"Word、Excel 和 PPT 不是三个互不相干的工具。一次完整办公交付通常是：材料先在 Word 中形成说明，数据在 Excel 中核对，最后用 PPT 汇报重点。WorkBuddy 的价值是协助处理重复劳动，并把验收要求贯穿整个过程。","frontmatter":{},"headers":[],"relativePath":"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 11 章 办公三件套：Word、Excel、PPT/index.md","filePath":"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 11 章 办公三件套：Word、Excel、PPT/index.md","lastUpdated":1784100816000}'),i={name:"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 11 章 办公三件套：Word、Excel、PPT/index.md"};function r(o,a,t,p,d,c){return l(),n("div",null,[...a[0]||(a[0]=[s(`<h1 id="第-11-章-word、excel、ppt-办公交付与格式检查" tabindex="-1">第 11 章 Word、Excel、PPT 办公交付与格式检查 <a class="header-anchor" href="#第-11-章-word、excel、ppt-办公交付与格式检查" aria-label="Permalink to &quot;第 11 章 Word、Excel、PPT 办公交付与格式检查&quot;">​</a></h1><p>Word、Excel 和 PPT 不是三个互不相干的工具。一次完整办公交付通常是：材料先在 Word 中形成说明，数据在 Excel 中核对，最后用 PPT 汇报重点。WorkBuddy 的价值是协助处理重复劳动，并把验收要求贯穿整个过程。</p><h2 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to &quot;适用场景&quot;">​</a></h2><ul><li>把零散材料整理为报告、说明或工作总结。</li><li>清洗表格、核对口径、计算指标并生成图表。</li><li>把报告和数据压缩为结构清楚的汇报材料。</li><li>检查文件命名、格式、引用、数字和交付清单。</li></ul><h2 id="任务目标" tabindex="-1">任务目标 <a class="header-anchor" href="#任务目标" aria-label="Permalink to &quot;任务目标&quot;">​</a></h2><p>让三个文件围绕同一套事实工作：Word 讲清楚，Excel 算准确，PPT 抓重点；任何数字都能回到原始数据，任何结论都能找到依据。</p><h2 id="输入材料" tabindex="-1">输入材料 <a class="header-anchor" href="#输入材料" aria-label="Permalink to &quot;输入材料&quot;">​</a></h2><ul><li>经授权使用的文字材料和表格。</li><li>输出对象、用途、截止时间和文件格式。</li><li>统计口径、参考模板和必须保留的内容。</li><li>验收人最关心的问题与禁止修改的部分。</li></ul><h2 id="执行步骤" tabindex="-1">执行步骤 <a class="header-anchor" href="#执行步骤" aria-label="Permalink to &quot;执行步骤&quot;">​</a></h2><h3 id="_1-先建立交付清单" tabindex="-1">1. 先建立交付清单 <a class="header-anchor" href="#_1-先建立交付清单" aria-label="Permalink to &quot;1. 先建立交付清单&quot;">​</a></h3><p>明确需要几个文件、各自用途、文件名和验收标准。没有明确要求时先生成提纲和样式预览，不直接制作终稿。</p><h3 id="_2-word-先结构-后润色" tabindex="-1">2. Word：先结构，后润色 <a class="header-anchor" href="#_2-word-先结构-后润色" aria-label="Permalink to &quot;2. Word：先结构，后润色&quot;">​</a></h3><p>先抽取事实、问题、措施和结论，再形成标题层级。要求 WorkBuddy 标记无来源数字和待确认表述，不用流畅语言掩盖材料缺口。</p><h3 id="_3-excel-先备份-后计算" tabindex="-1">3. Excel：先备份，后计算 <a class="header-anchor" href="#_3-excel-先备份-后计算" aria-label="Permalink to &quot;3. Excel：先备份，后计算&quot;">​</a></h3><p>保留原始数据表，另建处理表。记录清洗规则、公式口径、异常行和数据范围；关键计算使用抽样或独立方式复核。</p><h3 id="_4-ppt-一页只回答一个问题" tabindex="-1">4. PPT：一页只回答一个问题 <a class="header-anchor" href="#_4-ppt-一页只回答一个问题" aria-label="Permalink to &quot;4. PPT：一页只回答一个问题&quot;">​</a></h3><p>先列汇报故事线，再决定图表和版式。PPT 中的数字必须与 Excel 一致，结论必须与 Word 一致，不为“好看”删掉必要限制条件。</p><h3 id="_5-做跨文件检查" tabindex="-1">5. 做跨文件检查 <a class="header-anchor" href="#_5-做跨文件检查" aria-label="Permalink to &quot;5. 做跨文件检查&quot;">​</a></h3><p>核对标题、日期、版本、单位、数字、图表来源和附件。生成交付说明，列出已确认项和仍待确认项。</p><h2 id="合成示例" tabindex="-1">合成示例 <a class="header-anchor" href="#合成示例" aria-label="Permalink to &quot;合成示例&quot;">​</a></h2><p>假设需要整理一组虚构的“办公区域月度能耗数据”。交付物包括一份情况说明、一个数据核对表和一份五页汇报。WorkBuddy 可以检查缺失值、生成趋势图并组织汇报，但异常原因必须由经办人核实。</p><h3 id="可复制任务模板" tabindex="-1">可复制任务模板 <a class="header-anchor" href="#可复制任务模板" aria-label="Permalink to &quot;可复制任务模板&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请协助完成一组 Word、Excel、PPT 办公交付物。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>任务目的：{目的}</span></span>
<span class="line"><span>输入文件：{文件名}</span></span>
<span class="line"><span>输出对象：{读者}</span></span>
<span class="line"><span>交付要求：{Word/Excel/PPT及格式}</span></span>
<span class="line"><span>统计口径：{口径；没有则写“待确认”}</span></span>
<span class="line"><span>参考模板：{文件名；没有则写“未提供”}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>请先：</span></span>
<span class="line"><span>1. 列出材料缺口、风险和交付清单；</span></span>
<span class="line"><span>2. 给出 Word 提纲、Excel 处理规则和 PPT 故事线；</span></span>
<span class="line"><span>3. 等我确认后再生成文件；</span></span>
<span class="line"><span>4. 保留原始数据，不覆盖原件；</span></span>
<span class="line"><span>5. 输出跨文件数字核对表和待确认问题。</span></span></code></pre></div><h2 id="人工确认点" tabindex="-1">人工确认点 <a class="header-anchor" href="#人工确认点" aria-label="Permalink to &quot;人工确认点&quot;">​</a></h2><ul><li>输入材料和数据是否允许使用。</li><li>统计口径、公式、异常处理和结论是否正确。</li><li>格式是否使用了批准的模板或要求。</li><li>三个文件中的数字、日期和表述是否一致。</li><li>最终文件是否由责任人复核后再共享。</li></ul><h2 id="输出物与验收标准" tabindex="-1">输出物与验收标准 <a class="header-anchor" href="#输出物与验收标准" aria-label="Permalink to &quot;输出物与验收标准&quot;">​</a></h2><ul><li>Word：结构完整、事实有依据、问题与建议分开。</li><li>Excel：原始数据保留、处理步骤可复现、公式可检查。</li><li>PPT：重点清楚、图表可读、数据来源明确。</li><li>交付说明：列出版本、文件、口径、待确认项和使用范围。</li></ul><h2 id="常见弯路" tabindex="-1">常见弯路 <a class="header-anchor" href="#常见弯路" aria-label="Permalink to &quot;常见弯路&quot;">​</a></h2><ul><li><strong>直接生成三份终稿</strong>：跨文件数字容易打架。先确认共同事实表。</li><li><strong>在原表上直接清洗</strong>：错误难回退。原始表只读，处理表另存。</li><li><strong>PPT 只追求版式</strong>：结论失去证据。每张图注明口径和来源。</li></ul><h2 id="安全边界与可复用资产" tabindex="-1">安全边界与可复用资产 <a class="header-anchor" href="#安全边界与可复用资产" aria-label="Permalink to &quot;安全边界与可复用资产&quot;">​</a></h2><p>不上传未批准材料，不自动外发，不覆盖原件。可沉淀交付清单、数据处理记录、跨文件核对表和汇报结构模板。</p>`,31)])])}const P=e(i,[["render",r]]);export{u as __pageData,P as default};
